mapper.select:
SELECT 
    i.id,
    i.pressure,
    i.traffic as flow,
    i.temperature,
    i.shake as vibration,
    i.data_status,
    i.sensor_id,
    CONCAT(a.province, a.city, a.district) as area_name,
    p.name as pipeline_name,
    i.create_time as monitor_time
FROM inspection i
LEFT JOIN sensor s ON i.sensor_id = s.id
LEFT JOIN area a ON s.area_id = a.id
LEFT JOIN pipe p ON s.pipeline_id = p.id


        AND i.pressure >= #{minPressure}


        AND i.pressure <= #{maxPressure}


        AND i.traffic >= #{minFlow}


        AND i.traffic <= #{maxFlow}


        AND i.temperature >= #{minTemperature}


        AND i.temperature <= #{maxTemperature}


        AND i.shake >= #{minVibration}


        AND i.shake <= #{maxVibration}


        AND i.data_status = #{dataStatus}


        AND i.sensor_id = #{sensorId}


        AND p.name LIKE CONCAT('%', #{pipelineName}, '%')


        AND i.create_time >= #{monitorStartTime}


        AND i.create_time <= #{monitorEndTime}


ORDER BY i.create_time DESC

